import React, { useState, useEffect } from 'react';
import axios from 'axios';

const App = () => {
    const [userId, setUserId] = useState('');
    const [userName, setUserName] = useState('');
    const [message, setMessage] = useState('');

    const [users, setUsers] = useState([]);

    useEffect(() => {
      // Fetch users initially when the component mounts
        getUsers();

        // Setup interval to fetch users every second
        const interval = setInterval(() => {
            getUsers();
        }, 1000);

        // Cleanup the interval on component unmount
        return () => clearInterval(interval);
    }, []);

const enrollUser = async () => {
    try {
        const response = await axios.post('http://192.168.1.83:3001/enroll', { id: userId, name: userName });
        setMessage('User enrolled successfully');
    } catch (error) {
        setMessage(error.response.data.message); // Display the error message from the server
    }
};



    const getUsers = async () => {
      try {
          const response = await axios.get('http://192.168.1.83:3001/users');
          setUsers(response.data);
      } catch (error) {
        setMessage(error.response.data.message); // Display the error message from the server
      }
  };

    const checkFingerprint = async () => {
        try {
            const response = await axios.post('http://192.168.1.83:3001/check', { id: userId });
            setMessage(`Fingerprint matched for user: ${response.data.user}`);
        } catch (error) {
            if (error.response && error.response.status === 404) {
                setMessage('Fingerprint not matched');
            } else {
              setMessage(error.response.data.message); // Display the error message from the server
            }
        }
    };

    return (
        <div>
            <h1>Fingerprint Enrollment and Matching</h1>
            <div>
                <label>User ID:</label>
                <input type="text" value={userId} onChange={(e) => setUserId(e.target.value)} />
            </div>
            <div>
                <label>User Name:</label>
                <input type="text" value={userName} onChange={(e) => setUserName(e.target.value)} />
            </div>
            <button onClick={enrollUser}>Enroll User</button>
            <button onClick={checkFingerprint}>Check Fingerprint</button>
            <div>
                <h2>Message: {message}</h2>
            </div>

            <div>
                <h2>Users:</h2>
                <ul>
                    {users.map(user => (
                        <li key={user.id}>{user.name} User ID: {user.id}</li>
                    ))}
                </ul>
            </div>
        </div>
    );
};

export default App;
